/**
 * Type definitions for the EvalScore tool
 * Handles evaluation datasets and WorkIQ response scoring
 */

/**
 * Supported input file formats for evaluation datasets
 */
export type InputFormat = 'csv' | 'tsv' | 'xlsx' | 'json';

/**
 * Assertion types generated by EvalGen for deterministic response validation
 */
export type Assertion =
  | { type: 'must_contain'; value: string; wholeWord?: boolean }
  | { type: 'must_contain_any'; values: string[] }
  | { type: 'must_not_contain'; value: string };

/**
 * Result of evaluating a single assertion against an actual answer
 */
export interface AssertionResult {
  assertion: Assertion;
  passed: boolean;
  detail: string;
}

/**
 * A single row from the evaluation dataset
 * Represents one question-answer pair to be evaluated
 */
export interface EvalRow {
  /** The question/prompt to send to WorkIQ */
  prompt: string;

  /** The known-correct answer (ground truth) */
  expectedAnswer: string;

  /** Where in Microsoft 365 the answer is found */
  sourceLocation: string;

  /** WorkIQ's response (populated after querying the service) */
  actualAnswer: string;

  /** Semantic similarity score between expected and actual answers (0-100) */
  similarityScore?: number;

  /** Assertions to check against the actual answer (from EvalGen sidecar) */
  assertions?: Assertion[];

  /** Results of assertion checks (populated after scoring) */
  assertionResults?: AssertionResult[];
}

/**
 * Complete evaluation result containing all rows and metadata
 */
export interface EvalResult {
  /** Array of individual evaluation rows */
  rows: EvalRow[];

  /** Path to the input evaluation file */
  inputFile: string;

  /** Format of the input file (csv, tsv, xlsx, or json) */
  inputFormat: InputFormat;

  /** ISO 8601 timestamp when the evaluation was performed */
  timestamp: string;

  /** Optional system prompt used for the evaluation */
  systemPrompt?: string;
}

/**
 * Aggregated scoring results and statistics
 */
export interface ScoringResult {
  /** Total number of questions in the evaluation */
  totalQuestions: number;

  /** Average similarity score across all questions */
  averageScore: number;

  /** Minimum similarity score */
  minScore: number;

  /** Maximum similarity score */
  maxScore: number;

  /** Number of questions that passed the threshold */
  passCount: number;

  /** Number of questions that failed the threshold */
  failCount: number;

  /** Threshold used to determine pass/fail (0-100) */
  passThreshold: number;

  /** Total assertions evaluated (0 if no sidecar) */
  totalAssertions: number;

  /** Number of assertions that passed */
  assertionsPassed: number;

  /** Number of assertions that failed */
  assertionsFailed: number;
}

/**
 * CLI configuration and command-line options
 */
export interface CliOptions {
  /** Path to the evaluation dataset file (required) */
  input: string;

  /** System prompt provided inline as a string (optional) */
  systemPrompt?: string;

  /** Path to a file containing the system prompt (optional) */
  systemPromptFile?: string;

  /** Output directory for reports and results (default: './output') */
  outputDir: string;

  /** Similarity score threshold for pass/fail classification (default: 70, range: 0-100) */
  threshold: number;

  /** Microsoft 365 tenant ID to target for WorkIQ queries (optional) */
  tenantId?: string;

  /** Path to EvalGen sidecar JSON for assertion-aware scoring (optional) */
  sidecar?: string;
}
